export interface UserGestureEventContext {
  postedAt: number;
  event: Event | { timeStamp: number };
}

export type UserGestureHandler = (context: UserGestureEventContext) => void;

export function setHandler(element: EventTarget): void;

export function post(func: UserGestureHandler): void;

export function run(event?: Event | { timeStamp: number }): void;
